export default async function Image() {
  const fontData = Buffer.from(FONT_BASE64, 'base64');
  const photoDataUrl = `data:image/jpeg;base64,${PHOTO_BASE64}`;

  return new ImageResponse(
    (
      <div
        style={{
          width: '100%',
          height: '100%',
          display: 'flex',
          position: 'relative',
          background: '#12130f',
        }}
      >
        <img src={photoDataUrl}
          alt=""
          style={{
            position: 'absolute',
            inset: 0,
            width: '100%',
            height: '100%',
            objectFit: 'cover',
          }}
        />
        <div
          style={{
            position: 'absolute',
            inset: 0,
            display: 'flex',
            background:
              'linear-gradient(to top, rgba(18,19,15,0.95) 0%, rgba(18,19,15,0.6) 42%, rgba(18,19,15,0.15) 100%)',
          }}
        />
        <div
          style={{
            position: 'absolute',
            bottom: 56,
            left: 64,
            display: 'flex',
            flexDirection: 'column',
          }}
        >
          <div style={{ fontSize: 60, color: '#F3EFE6', fontFamily: 'Noto Sans Georgian' }}>
            Buknari Villa
          </div>
          <div
            style={{
              fontSize: 28,
              color: '#CBBFA4',
              marginTop: 14,
              fontFamily: 'Noto Sans Georgian',
            }}
          >
            ვილების და სახლების გაქირავება ბუკნარში
          </div>
          <div
            style={{
              fontSize: 22,
              color: '#2F7FB5',
              marginTop: 18,
              fontFamily: 'Noto Sans Georgian',
            }}
          >
            buknarivilla.ge
          </div>
        </div>
      </div>
    ),
    {
      ...size,
      fonts: [
        {
          name: 'Noto Sans Georgian',
          data: fontData,
          style: 'normal',
          weight: 400,
        },
      ],
    }
  );
}
